                                            { method:"POST",   path:"/deploy", color:"text-blue-400 bg-blue-400/10"       },
                                            { method:"PUT",    path:"/config", color:"text-amber-400 bg-amber-400/10"     },
                                            { method:"DELETE", path:"/cache",  color:"text-red-400 bg-red-400/10"         },
