                                            </div>
                                        ))}
                                    </div>
                                    <div className="px-2.5 pb-2.5 pt-1.5 flex items-center gap-2 border-t border-white/5 flex-shrink-0">
                                        <div className="flex-1 h-1 rounded-full overflow-hidden" style={{ background:"rgba(255,255,255,0.05)" }}>
                                            <div className="h-full w-3/4 rounded-full bg-gradient-to-r from-blue-500 to-violet-500" />
                                        </div>
                                        <span className="text-[6px] text-white/25 font-mono flex-shrink-0">124ms</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/*
                        Clock — centered on the gap between row 1 and row 2.
                        Positioned absolute relative to the row-2 motion.div wrapper.
                        top-0 + -translate-y-1/2 = sits exactly half above, half below
                        the top edge of the bottom card, which aligns with the bottom
                        edge of the top card — perfect for the cutout notches.

                        Sizes must match --mask-radius × 2 in globals.css:
                          md  → w-56  h-56  (14rem) — mask-radius: calc(7rem  + 4px)
                          lg  → w-72  h-72  (18rem) — mask-radius: calc(9rem  + 4px)
                          xl  → w-[22rem]   (22rem) — mask-radius: calc(11rem + 4px)
                    */}
                    <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 z-30 hidden md:block w-56 h-56 lg:w-72 lg:h-72 xl:w-[22rem] xl:h-[22rem]">
                        <Clock />
                    </div>

                    {/* Mobile clock — inline below content */}
                    <div className="w-36 h-36 mx-auto mt-6 relative z-30 md:hidden">
                        <Clock />
                    </div>
                </motion.div>
            </div>

            {/* ── Skills section ──────────────────────────────────────────── */}
            <Skills />

        </section>
    );
}

"use client";

import { useEffect, useState } from "react";
import Particles, { initParticlesEngine } from "@tsparticles/react";
import { type Container, type ISourceOptions } from "@tsparticles/engine";
import { loadSlim } from "@tsparticles/slim";
import { useTheme } from "next-themes";

export default function ParticleBackground() {
    const [init, setInit] = useState(false);
    const { resolvedTheme } = useTheme();
    const isLight = resolvedTheme === "light";

    // Initialize the tsParticles engine
    useEffect(() => {
        initParticlesEngine(async (engine) => {
            // loadSlim is a smaller bundle that provides basic shapes and movement.
            await loadSlim(engine);
        }).then(() => {
            setInit(true);
        });
    }, []);

    const particlesLoaded = async (container?: Container): Promise<void> => {
        // Optional debugging if needed
        // console.log("Particles container loaded", container);
    };

    const options: ISourceOptions = {
        background: {
            color: {
                value: "transparent",
            },
        },
        fpsLimit: 60,
        interactivity: {
            events: {
                // Keep interactivity minimal or disabled so it doesn't distract.
                // We're disabling hover/click to ensure the background stays passive.
            },
        },
        particles: {
            color: {
                // Adapt particle colors to the current theme
                value: isLight ? ["#000000", "#333333"] : ["#ffffff", "#e0f2fe"],
            },
            links: {
                // Adapt linking lines color and opacity based on theme
                color: isLight ? "#000000" : "#ffffff",
                distance: 150,
                enable: true,
                opacity: isLight ? 0.2 : 0.1, // Slightly darker in light mode for visibility
                width: 1,
            },
            move: {
                direction: "none",
                enable: true,
                outModes: {
                    default: "bounce", // Bounce off walls to keep particles in view
                },
                random: false,
                speed: 0.6, // Very slow, elegant drift
                straight: false,
            },
            number: {
                density: {
                    enable: true,
                    // width: 800, // Replaced by height/width properties below internally usually, but 'area' is modern syntax if supported. Using default responsive density.
                },
                value: 45, // Not too crowded
            },
            opacity: {
                value: 0.3, // Soft glowing dots
            },
            shape: {
                type: "circle",
            },
            size: {
                value: { min: 1, max: 2.5 }, // Small dots
            },
        },
        detectRetina: true,
    };

    if (!init) {
        return null;
    }

    return (
        <div className="fixed inset-0 z-[-10] pointer-events-none data-particles-bg">
            <Particles
                key={resolvedTheme} // Force re-render on theme change
                id="tsparticles"
                particlesLoaded={particlesLoaded}
                options={options}
                className="w-full h-full"
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect, useCallback, useRef, TouchEvent } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ExternalLink, Github, ChevronLeft, ChevronRight } from "lucide-react";

const projects = [
    {
