                <div className="rounded-2xl border border-neutral-200 dark:border-white/8 bg-white/60 dark:bg-[#0a0a0a] p-6 min-h-[340px] flex flex-col">
                    <RotatingQuote />
                </div>
            </div>
        </motion.div>
    );
}

